242	export async function fetchTree(
243	  style: string,
244	  tree: z.infer<typeof registryIndexSchema>
245	) {
246	  try {
247	    const paths = tree.map((item) => `styles/${style}/${item.name}.json`)
248	    const results = await fetchRegistry(paths)
249	    return results.map((result) => registryItemSchema.parse(result))
250	  } catch (error) {
