Perfect! I now have a comprehensive picture of the React context patterns used in this codebase. Let me create a summary report for you.

## React Context Pattern Report for Stepper Component

I found **5 excellent examples** of custom React context usage in `/apps/v4/registry/new-york-v4/ui/`. Here are the key patterns you should replicate for your Stepper component:

---

### Pattern Overview: Three Main Approaches

#### **1. SIDEBAR.TSX** - Most Complex Example (Recommended for Stepper)
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473380920-snxt2p/apps/v4/registry/new-york-v4/ui/sidebar.tsx`

**Context Structure:**
```typescript
type SidebarContextProps = {
  state: "expanded" | "collapsed"
  open: boolean
  setOpen: (open: boolean) => void
  openMobile: boolean
  setOpenMobile: (open: boolean) => void
  isMobile: boolean
  toggleSidebar: () => void
}

const SidebarContext = React.createContext<SidebarContextProps | null>(null)
```

**Custom Hook Pattern:**
```typescript
function useSidebar() {
  const context = React.useContext(SidebarContext)
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider.")
  }
  return context
}
```

**Provider Component (with value memoization):**
```typescript
function SidebarProvider({
  defaultOpen = true,
  open: openProp,
  onOpenChange: setOpenProp,
  className,
  style,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
}) {
  // ... state setup ...

  const contextValue = React.useMemo<SidebarContextProps>(
    () => ({
      state,
      open,
      setOpen,
      isMobile,
      openMobile,
      setOpenMobile,
      toggleSidebar,
    }),
    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
  )

  return (
    <SidebarContext.Provider value={contextValue}>
      {/* Provider wrapper JSX */}
      {children}
    </SidebarContext.Provider>
  )
}
```

**Sub-component Pattern (uses hook to consume context):**
```typescript
function SidebarTrigger({
  className,
  onClick,
  ...props
}: React.ComponentProps<typeof Button>) {
  const { toggleSidebar } = useSidebar()  // ← Hook-based consumption

  return (
    <Button
      onClick={(event) => {
        onClick?.(event)
        toggleSidebar()
      }}
      {...props}
    >
      {/* content */}
    </Button>
  )
}
```

**Key Features for Stepper:**
- Typed context with explicit null union
- Custom hook with runtime error checking
- `useMemo` to prevent unnecessary re-renders
- Provider supports both controlled and uncontrolled modes
- All sub-components use the custom hook pattern
- Export the custom hook alongside component exports

---

#### **2. CAROUSEL.TSX** - Lighter Version
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473380920-snxt2p/apps/v4/registry/new-york-v4/ui/carousel.tsx`

**Context Structure:**
```typescript
type CarouselContextProps = {
  carouselRef: ReturnType<typeof useEmblaCarousel>[0]
  api: ReturnType<typeof useEmblaCarousel>[1]
  scrollPrev: () => void
  scrollNext: () => void
  canScrollPrev: boolean
  canScrollNext: boolean
} & CarouselProps

const CarouselContext = React.createContext<CarouselContextProps | null>(null)

function useCarousel() {
  const context = React.useContext(CarouselContext)
  if (!context) {
    throw new Error("useCarousel must be used within a <Carousel />")
  }
  return context
}
```

**Provider (simpler - no useMemo):**
```typescript
return (
  <CarouselContext.Provider
    value={{
      carouselRef,
      api: api,
      opts,
      orientation: orientation || (opts?.axis === "y" ? "vertical" : "horizontal"),
      scrollPrev,
      scrollNext,
      canScrollPrev,
      canScrollNext,
    }}
  >
    {/* JSX */}
  </CarouselContext.Provider>
)
```

---

#### **3. CHART.TSX** - Minimal Version
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473380920-snxt2p/apps/v4/registry/new-york-v4/ui/chart.tsx`

**Context Structure:**
```typescript
type ChartContextProps = {
  config: ChartConfig
}

const ChartContext = React.createContext<ChartContextProps | null>(null)

function useChart() {
  const context = React.useContext(ChartContext)
  if (!context) {
    throw new Error("useChart must be used within a <ChartContainer />")
  }
  return context
}
```

**Provider (direct object):**
```typescript
return (
  <ChartContext.Provider value={{ config }}>
    {/* JSX */}
  </ChartContext.Provider>
)
```

---

#### **4. TOGGLE-GROUP.TSX** - Simplest Pattern
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473380920-snxt2p/apps/v4/registry/new-york-v4/ui/toggle-group.tsx`

**Context with default value (no null):**
```typescript
const ToggleGroupContext = React.createContext<
  VariantProps<typeof toggleVariants> & {
    spacing?: number
  }
>({
  size: "default",
  variant: "default",
  spacing: 0,
})

function ToggleGroupItem({...}) {
  const context = React.useContext(ToggleGroupContext)
  // No error check needed - has default
  return (
    <ToggleGroupPrimitive.Item
      data-variant={context.variant || variant}
      data-size={context.size || size}
      // ...
    />
  )
}
```

---

#### **5. FORM.TSX** - Multiple Contexts
**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775473380920-snxt2p/apps/v4/registry/new-york-v4/ui/form.tsx`

**Multiple contexts pattern:**
```typescript
type FormFieldContextValue<...> = {
  name: TName
}

const FormFieldContext = React.createContext<FormFieldContextValue>(
  {} as FormFieldContextValue
)

type FormItemContextValue = {
  id: string
}

const FormItemContext = React.createContext<FormItemContextValue>(
  {} as FormItemContextValue
)

// Nested context consumer hook
const useFormField = () => {
  const fieldContext = React.useContext(FormFieldContext)
  const itemContext = React.useContext(FormItemContext)
  // Compose data from multiple contexts
  return { ...fieldContext, ...itemContext, ... }
}
```

---

## Recommendation for Your Stepper Component

**Use the SIDEBAR.TSX pattern** as your template because:

1. ✓ Complex shared state (currentStep, orientation, size, variant)
2. ✓ Controlled + uncontrolled mode support
3. ✓ Multiple sub-components that need context (Step, StepLabel, StepContent, etc.)
4. ✓ State updates (setCurrentStep, goToStep, nextStep, prevStep)
5. ✓ Memoized context value to prevent cascading re-renders
6. ✓ Strong runtime error checking with custom hook

**Stepper Template Structure:**
```typescript
type StepperContextProps = {
  currentStep: number
  orientation: "horizontal" | "vertical"
  size?: "sm" | "md" | "lg"
  variant?: "default" | "card"
  goToStep: (step: number) => void
  nextStep: () => void
  prevStep: () => void
  isStepCompleted: (step: number) => boolean
}

const StepperContext = React.createContext<StepperContextProps | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function Stepper({ currentStep: currentStepProp, onCurrentStepChange, ...props }: ...) {
  // State management
  const [_currentStep, _setCurrentStep] = useState(0)
  const currentStep = currentStepProp ?? _currentStep

  const contextValue = React.useMemo<StepperContextProps>(
    () => ({
      currentStep,
      orientation: "horizontal",
      goToStep,
      nextStep,
      prevStep,
      isStepCompleted,
    }),
    [currentStep, /* dependencies */]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      {children}
    </StepperContext.Provider>
  )
}
```

---

All source files are production-grade, fully typed, and ready to examine. The sidebar.tsx in particular is comprehensive and serves a similar compositional pattern to what a Stepper needs.

