"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

type StepperOrientation = "horizontal" | "vertical"
type StepperState = "active" | "completed" | "inactive"

// ---------------------------------------------------------------------------
// StepperContext — shared across the entire stepper
// ---------------------------------------------------------------------------

type StepperContextValue = {
  activeStep: number
  orientation: StepperOrientation
  setActiveStep: (step: number) => void
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// Re-export as the public hook consumers can use for imperative control
const useStepper = useStepperContext

// ---------------------------------------------------------------------------
// StepperItemContext — shared within a single StepperItem
// ---------------------------------------------------------------------------

type StepperItemContextValue = {
  step: number
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItemContext() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error(
      "useStepperItem must be used within a <StepperItem />"
    )
  }
  return context
}

// ---------------------------------------------------------------------------
// Stepper (root)
// ---------------------------------------------------------------------------

function Stepper({
  activeStep: activeStepProp,
  defaultActiveStep = 0,
  onActiveStepChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  activeStep?: number
  defaultActiveStep?: number
  onActiveStepChange?: (step: number) => void
  orientation?: StepperOrientation
}) {
  const [_activeStep, _setActiveStep] = React.useState(defaultActiveStep)

  // Support both controlled and uncontrolled modes
  const activeStep = activeStepProp ?? _activeStep

  const setActiveStep = React.useCallback(
    (step: number) => {
      if (activeStepProp === undefined) {
        _setActiveStep(step)
      }
      onActiveStepChange?.(step)
    },
    [activeStepProp, onActiveStepChange]
  )

  const contextValue = React.useMemo<StepperContextValue>(
    () => ({ activeStep, orientation, setActiveStep }),
    [activeStep, orientation, setActiveStep]
  )

  return (
    <StepperContext.Provider value={contextValue}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperList — optional semantic wrapper for the step header row / column
// ---------------------------------------------------------------------------

function StepperList({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepperContext()

  return (
    <div
      data-slot="stepper-list"
      data-orientation={orientation}
      className={cn(
        "flex items-center",
        orientation === "vertical" && "flex-col items-start",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperItem — wraps one step; provides StepperItemContext
// ---------------------------------------------------------------------------

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  step: number
  disabled?: boolean
}) {
  const { activeStep, orientation } = useStepperContext()

  const isActive = activeStep === step
  const isCompleted = activeStep > step
  const state: StepperState = isActive
    ? "active"
    : isCompleted
      ? "completed"
      : "inactive"

  const itemContextValue = React.useMemo<StepperItemContextValue>(
    () => ({ step, isActive, isCompleted, isDisabled: disabled }),
    [step, isActive, isCompleted, disabled]
  )

  return (
    <StepperItemContext.Provider value={itemContextValue}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled ? "true" : undefined}
        className={cn(
          "group/stepper-item flex items-center",
          orientation === "vertical" && "w-full flex-col items-start",
          disabled && "pointer-events-none opacity-50",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger — clickable element that activates a step
// ---------------------------------------------------------------------------

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { setActiveStep } = useStepperContext()
  const { step, isActive, isCompleted, isDisabled } = useStepperItemContext()

  const state: StepperState = isActive
    ? "active"
    : isCompleted
      ? "completed"
      : "inactive"

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      type="button"
      disabled={isDisabled}
      onClick={() => setActiveStep(step)}
      className={cn(
        "inline-flex items-center gap-2 rounded-md text-sm font-medium outline-none transition-colors",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        "data-[state=active]:text-foreground",
        "data-[state=completed]:text-muted-foreground",
        "data-[state=inactive]:text-muted-foreground",
        className
      )}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperIndicator — circular badge showing step number or ✓ icon
// ---------------------------------------------------------------------------

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = useStepperItemContext()

  const state: StepperState = isActive
    ? "active"
    : isCompleted
      ? "completed"
      : "inactive"

  return (
    <span
      data-slot="stepper-indicator"
      data-state={state}
      className={cn(
        "flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-medium transition-colors",
        "data-[state=inactive]:border-input data-[state=inactive]:bg-background data-[state=inactive]:text-muted-foreground",
        "data-[state=active]:border-primary data-[state=active]:bg-primary data-[state=active]:text-primary-foreground",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ?? (isCompleted ? (
        <CheckIcon className="size-4" />
      ) : (
        <span>{step + 1}</span>
      ))}
    </span>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle — step label text
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive, isCompleted } = useStepperItemContext()

  const state: StepperState = isActive
