"use client"

import * as React from "react"

import { Button } from "@/styles/radix-nova/ui/button"
import {
  Stepper,
  StepperDescription,
  StepperIndicator,
  StepperItem,
  StepperList,
  StepperPanel,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/styles/radix-nova/ui/stepper"

const steps = [
  {
    title: "Account",
    description: "Create your account",
    content: "Enter your email address and choose a secure password to get started.",
  },
  {
    title: "Profile",
    description: "Set up your profile",
    content: "Add your name, profile photo, and a short bio so others can find you.",
  },
  {
    title: "Review",
    description: "Confirm and submit",
    content: "Everything looks good! Review your details and click Finish to complete setup.",
  },
]

export function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-xl flex-col gap-8">
      <Stepper activeStep={activeStep} onActiveStepChange={setActiveStep}>
        <StepperList className="w-full">
          {steps.map((step, index) => (
            <React.Fragment key={index}>
              <StepperItem step={index} className="flex-1">
                <StepperTrigger className="flex-col gap-1.5 sm:flex-row sm:gap-2">
                  <StepperIndicator />
                  <div className="flex flex-col gap-0.5 text-left">
                    <StepperTitle>{step.title}</StepperTitle>
                    <StepperDescription className="hidden sm:block">
                      {step.description}
                    </StepperDescription>
                  </div>
                </StepperTrigger>
              </StepperItem>
              {index < steps.length - 1 && <StepperSeparator />}
            </React.Fragment>
          ))}
        </StepperList>

        {steps.map((step, index) => (
          <StepperPanel
            key={index}
            step={index}
            className="rounded-lg border bg-card p-4 text-sm text-muted-foreground"
          >
            {step.content}
          </StepperPanel>
        ))}
      </Stepper>

      <div className="flex items-center justify-between gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((s) => Math.max(0, s - 1))}
          disabled={activeStep === 0}
        >
          Back
        </Button>
        <span className="text-sm text-muted-foreground">
          Step {activeStep + 1} of {steps.length}
        </span>
        <Button
          onClick={() =>
            setActiveStep((s) => Math.min(steps.length - 1, s + 1))
          }
          disabled={activeStep === steps.length - 1}
        >
          {activeStep === steps.length - 2 ? "Finish" : "Next"}
        </Button>
      </div>
    </div>
  )
}

